思路：模拟
创建一个长度为
8
的状态数组，初始全为
0
。
按顺序每两个字符解析一条指令：
Lx
：将第
x
位设为
1
Dx
：将第
x
位设为
0
Tx
：将第
x
位取反
全部执行完后，将最终
8
位二进制转换为十进制整数返回。
C++
#include<iostream>
#include<vector>
#include<string>
#include <utility>
#include <sstream>
#include<algorithm>
#include<cmath>
#include<map>
using namespace std;
int controlInstruct(string& instruct) {
vector<int>
bits(8, 0);
for (int i = 0; i <
instruct.size(); i+=2) {
char c = instruct[i];
int pos = instruct[i+1] - '0';
//
点亮变为
1
if (c == 'L') {
bits[pos] = 1;
//
熄灭
} else if (c =='D') {
bits[pos] = 0;
//
切换
} else if (c == 'T'){
bits[pos] ^= 1;
}
}
int res = 0;
for (int i = 7; i >=
0; i--) {
res = res * 2 + bits[i];
}
return res;
}
int main() {
string input;
getline(cin, input);
int res =
controlInstruct(input);
cout << res;
return 0;
}
