bits[pos] ^= 1;
}
}
let res = 0;
for (let i = 7; i >=
0; i--) {
res = res * 2 + bits[i];
}
return res;
}
const rl = readline.createInterface({
input: process.stdin,
output: process.stdout
});
rl.on('line', (input) => {
console.log(controlInstruct(input.trim()));
});
